/// The idb companion service definition.
///
/// To build a server, implement a class that conforms to this protocol.
internal protocol Idb_CompanionServiceProvider: CallHandlerProvider {
  var interceptors: Idb_CompanionServiceServerInterceptorFactoryProtocol? { get }

  /// Management
  func connect(request: Idb_ConnectRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ConnectResponse>

  func debugserver(context: StreamingResponseCallContext<Idb_DebugServerResponse>) -> EventLoopFuture<(StreamEvent<Idb_DebugServerRequest>) -> Void>

  func dap(context: StreamingResponseCallContext<Idb_DapResponse>) -> EventLoopFuture<(StreamEvent<Idb_DapRequest>) -> Void>

  func describe(request: Idb_TargetDescriptionRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_TargetDescriptionResponse>

  func install(context: StreamingResponseCallContext<Idb_InstallResponse>) -> EventLoopFuture<(StreamEvent<Idb_InstallRequest>) -> Void>

  func instruments_run(context: StreamingResponseCallContext<Idb_InstrumentsRunResponse>) -> EventLoopFuture<(StreamEvent<Idb_InstrumentsRunRequest>) -> Void>

  func log(request: Idb_LogRequest, context: StreamingResponseCallContext<Idb_LogResponse>) -> EventLoopFuture<GRPCStatus>

  func xctrace_record(context: StreamingResponseCallContext<Idb_XctraceRecordResponse>) -> EventLoopFuture<(StreamEvent<Idb_XctraceRecordRequest>) -> Void>

  /// Interaction
  func accessibility_info(request: Idb_AccessibilityInfoRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_AccessibilityInfoResponse>

  func focus(request: Idb_FocusRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_FocusResponse>

  func hid(context: UnaryResponseCallContext<Idb_HIDResponse>) -> EventLoopFuture<(StreamEvent<Idb_HIDEvent>) -> Void>

  func open_url(request: Idb_OpenUrlRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_OpenUrlRequest>

  func set_location(request: Idb_SetLocationRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_SetLocationResponse>

  func send_notification(request: Idb_SendNotificationRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_SendNotificationResponse>

  func simulate_memory_warning(request: Idb_SimulateMemoryWarningRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_SimulateMemoryWarningResponse>

  /// Settings
  func approve(request: Idb_ApproveRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ApproveResponse>

  func revoke(request: Idb_RevokeRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_RevokeResponse>

  func clear_keychain(request: Idb_ClearKeychainRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ClearKeychainResponse>

  func contacts_update(request: Idb_ContactsUpdateRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ContactsUpdateResponse>

  func setting(request: Idb_SettingRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_SettingResponse>

  func get_setting(request: Idb_GetSettingRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_GetSettingResponse>

  func list_settings(request: Idb_ListSettingRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ListSettingResponse>

  /// App
  func launch(context: StreamingResponseCallContext<Idb_LaunchResponse>) -> EventLoopFuture<(StreamEvent<Idb_LaunchRequest>) -> Void>

  func list_apps(request: Idb_ListAppsRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ListAppsResponse>

  func terminate(request: Idb_TerminateRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_TerminateResponse>

  func uninstall(request: Idb_UninstallRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_UninstallResponse>

  /// Video/Audio
  func add_media(context: UnaryResponseCallContext<Idb_AddMediaResponse>) -> EventLoopFuture<(StreamEvent<Idb_AddMediaRequest>) -> Void>

  func record(context: StreamingResponseCallContext<Idb_RecordResponse>) -> EventLoopFuture<(StreamEvent<Idb_RecordRequest>) -> Void>

  func screenshot(request: Idb_ScreenshotRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_ScreenshotResponse>

  func get_main_screen_iosurface(request: Idb_GetMainScreenIOSurfaceRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_GetMainScreenIOSurfaceResponse>

  func video_stream(context: StreamingResponseCallContext<Idb_VideoStreamResponse>) -> EventLoopFuture<(StreamEvent<Idb_VideoStreamRequest>) -> Void>

  /// Crash Operations
  func crash_delete(request: Idb_CrashLogQuery, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_CrashLogResponse>

  func crash_list(request: Idb_CrashLogQuery, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_CrashLogResponse>

  func crash_show(request: Idb_CrashShowRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_CrashShowResponse>

  /// xctest operations
  func xctest_list_bundles(request: Idb_XctestListBundlesRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_XctestListBundlesResponse>

  func xctest_list_tests(request: Idb_XctestListTestsRequest, context: StatusOnlyCallContext) -> EventLoopFuture<Idb_XctestListTestsResponse>

  func xctest_run(request: Idb_XctestRunRequest, context: StreamingResponseCallContext<Idb_XctestRunResponse>) -> EventLoopFuture<GRPCStatus>

