  func push(context: UnaryResponseCallContext<Idb_PushResponse>) -> EventLoopFuture<(StreamEvent<Idb_PushRequest>) -> Void>

  func tail(context: StreamingResponseCallContext<Idb_TailResponse>) -> EventLoopFuture<(StreamEvent<Idb_TailRequest>) -> Void>
}

